SELECT a.*, u.NAME AS USER_NAME
FROM R_ACTIVITY_LOG_T a
LEFT JOIN R_USER_T u ON a.USER_ID = u.USER_ID


        AND a.ACTION_TYPE = #{actionType}


        AND a.TARGET_TYPE = #{targetType}


        AND a.USER_ID = #{userId}


        AND a.CREATED_AT >= #{startDate}


        AND a.CREATED_AT <= #{endDate}


        AND (u.NAME LIKE CONCAT('%', #{search}, '%')
             OR a.TARGET_NAME LIKE CONCAT('%', #{search}, '%')
             OR a.REQUEST_URI LIKE CONCAT('%', #{search}, '%'))


ORDER BY

    u.NAME
    a.ACTION_TYPE
    a.TARGET_TYPE
    a.CREATED_AT
    a.CREATED_AT

ASC
DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM R_ACTIVITY_LOG_T a
LEFT JOIN R_USER_T u ON a.USER_ID = u.USER_ID


        AND a.ACTION_TYPE = #{actionType}


        AND a.TARGET_TYPE = #{targetType}


        AND a.USER_ID = #{userId}


        AND a.CREATED_AT >= #{startDate}


        AND a.CREATED_AT <= #{endDate}


        AND (u.NAME LIKE CONCAT('%', #{search}, '%')
             OR a.TARGET_NAME LIKE CONCAT('%', #{search}, '%')
             OR a.REQUEST_URI LIKE CONCAT('%', #{search}, '%'))

SELECT a.*, u.NAME AS USER_NAME
FROM R_ACTIVITY_LOG_T a
LEFT JOIN R_USER_T u ON a.USER_ID = u.USER_ID
WHERE a.HISTORY_ID = #{historyId}
ORDER BY a.CREATED_AT DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM R_ACTIVITY_LOG_T
WHERE HISTORY_ID = #{historyId}
